public class CompteBancaire
{
    private decimal solde;

    public decimal Solde 
    { 
        get { return solde; }
        private set { solde = value; }
    }

    private string titulaire;
    public string Titulaire
    {
        get { return titulaire; }
        set 
        {
            if (string.IsNullOrWhiteSpace(value))
                throw new ArgumentException("Titulaire requis");
            titulaire = value;
        }
    }

    public CompteBancaire(string titulaire, decimal soldeInitial)
    {
        Titulaire = titulaire;
        Solde = soldeInitial;
    }

    public void Deposer(decimal montant)
    {
        if (montant <= 0)
            throw new ArgumentException("Montant positif requis");
        Solde += montant;
    }

    public void Retirer(decimal montant)
    {
        if (montant <= 0)
            throw new ArgumentException("Montant positif requis");
        if (montant > Solde)
            throw new InvalidOperationException("Fonds insuffisants");
        Solde -= montant;
    }
}
