public class Rectangle
{
    private double largeur;
    private double hauteur;

    public double Largeur
    {
        get { return largeur; }
        set
        {
            if (value <= 0)
                throw new ArgumentException("Largeur doit être positive");
            largeur = value;
        }
    }

    public double Hauteur
    {
        get { return hauteur; }
        set
        {
            if (value <= 0)
                throw new ArgumentException("Hauteur doit être positive");
            hauteur = value;
        }
    }

    public double Aire
    {
        get { return Largeur * Hauteur; }
    }

    public double Perimetre
    {
        get { return 2 * (Largeur + Hauteur); }
    }

    public bool EstCarre
    {
        get { return Largeur == Hauteur; }
    }
}
