public class Employe
{
    public string Matricule { get; private set; }
    public string Nom { get; private set; }
    public string Prenom { get; private set; }

    private decimal salaireBase;
    public decimal SalaireBase
    {
        get { return salaireBase; }
        private set
        {
            if (value < 0)
                throw new ArgumentException("Salaire base invalide");
            salaireBase = value;
        }
    }

    private int ancienneteAnnees;
    public int AncienneteAnnees
    {
        get { return ancienneteAnnees; }
        private set
        {
            if (value < 0)
                throw new ArgumentException("Ancienneté négative");
            ancienneteAnnees = value;
        }
    }

    public decimal Prime
    {
        get { return SalaireBase * 0.05m * AncienneteAnnees; }
    }

    public decimal SalaireTotal
    {
        get { return SalaireBase + Prime; }
    }

    public Employe(string matricule, string nom, string prenom, decimal salaireBase, int ancienneteAnnees)
    {
        if (string.IsNullOrWhiteSpace(matricule))
            throw new ArgumentException("Matricule requis");
        if (string.IsNullOrWhiteSpace(nom))
            throw new ArgumentException("Nom requis");
        if (string.IsNullOrWhiteSpace(prenom))
            throw new ArgumentException("Prénom requis");

        Matricule = matricule;
        Nom = nom;
        Prenom = prenom;
        SalaireBase = salaireBase;
        AncienneteAnnees = ancienneteAnnees;
    }
}
